import React, { useState, useEffect } from 'react';

// Movie poster images mapping by title
const movieImageMap = {
  'Inception': '/images/inception.jpg',
  'The Dark Knight': '/images/the-dark-knight.jpg',
  'Interstellar': '/images/interstellar.jpg',
  'The Room': '/images/the-room.jpg',
  'Titanic': '/images/titanic.jpg',
};

// Fallback images for random assignments
const fallbackImages = [
  'https://images.unsplash.com/photo-1489599849228-13e67d91ebff?w=300&h=450&fit=crop',
  'https://images.unsplash.com/photo-1517604931442-7e0c6ed2963c?w=300&h=450&fit=crop',
  'https://images.unsplash.com/photo-1594908900066-3f47337549d8?w=300&h=450&fit=crop',
  'https://images.unsplash.com/photo-1493225457124-a3eb161ffa5f?w=300&h=450&fit=crop',
  'https://images.unsplash.com/photo-1513941231169-2b8d6ce5dd21?w=300&h=450&fit=crop',
];

const getMovieImage = (movieTitle) => {
  return movieImageMap[movieTitle] || fallbackImages[Math.floor(Math.random() * fallbackImages.length)];
};

const MovieManager = () => {
  const [movies, setMovies] = useState([]);
  const [movieImages, setMovieImages] = useState({});
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    title: '',
    genre: '',
    rating: '',
    recommendation: 'Yes'
  });
  const [editingId, setEditingId] = useState(null);
  const [filterRating, setFilterRating] = useState('');

  useEffect(() => {
    fetchMovies();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [filterRating]);

  const fetchMovies = async () => {
    setLoading(true);
    try {
      const url = filterRating
        ? `http://localhost:5000/movies?rating=${filterRating}`
        : 'http://localhost:5000/movies';
      const response = await fetch(url);
      const data = await response.json();
      setMovies(data);
      
      // Assign images to each movie based on title
      const images = {};
      data.forEach(movie => {
        if (!movieImages[movie.id]) {
          images[movie.id] = getMovieImage(movie.title);
        }
      });
      setMovieImages(prev => ({ ...prev, ...images }));
    } catch (error) {
      console.error('Error fetching movies:', error);
      alert('Failed to fetch movies');
    }
    setLoading(false);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.title || !formData.genre || !formData.rating) {
      alert('All fields are required');
      return;
    }

    try {
      if (editingId) {
        const response = await fetch(`http://localhost:5000/movies/${editingId}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            title: formData.title,
            genre: formData.genre,
            rating: parseInt(formData.rating),
            recommendation: formData.recommendation
          })
        });
        const updated = await response.json();
        setMovies(movies.map(m => m.id === editingId ? updated : m));
        setEditingId(null);
      } else {
        const response = await fetch('http://localhost:5000/movies', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            title: formData.title,
            genre: formData.genre,
            rating: parseInt(formData.rating),
            recommendation: formData.recommendation
          })
        });
        const newMovie = await response.json();
        setMovies([...movies, newMovie]);
        setMovieImages(prev => ({ ...prev, [newMovie.id]: getMovieImage(newMovie.title) }));
      }
      setFormData({ title: '', genre: '', rating: '', recommendation: 'Yes' });
      setShowForm(false);
    } catch (error) {
      console.error('Error saving movie:', error);
      alert('Failed to save movie');
    }
  };

  const handleEdit = (movie) => {
    setFormData(movie);
    setEditingId(movie.id);
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this movie?')) return;
    try {
      await fetch(`http://localhost:5000/movies/${id}`, { method: 'DELETE' });
      setMovies(movies.filter(m => m.id !== id));
    } catch (error) {
      console.error('Error deleting movie:', error);
      alert('Failed to delete movie');
    }
  };

  const genreColors = {
    'Sci-Fi': 'from-blue-600 to-cyan-600',
    'Action': 'from-red-600 to-orange-600',
    'Drama': 'from-purple-600 to-pink-600',
    'Comedy': 'from-yellow-600 to-orange-600',
    'Horror': 'from-gray-800 to-red-900',
    'Romance': 'from-pink-600 to-rose-600',
  };

  const getRatingColor = (rating) => {
    if (rating >= 4) return 'text-green-400';
    if (rating >= 3) return 'text-yellow-400';
    return 'text-red-400';
  };

  return (
    <div className="w-full">
      {/* Top Section with Title and Add Button */}
      <div className="mb-12">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-4xl font-bold text-white mb-2">🎞️ Movie Collection</h2>
            <p className="text-gray-400">Manage and organize your favorite movies</p>
          </div>
          <button
            onClick={() => {
              setShowForm(!showForm);
              if (!showForm) {
                setEditingId(null);
                setFormData({ title: '', genre: '', rating: '', recommendation: 'Yes' });
              }
            }}
            className="bg-gradient-to-r from-yellow-500 to-yellow-600 hover:from-yellow-600 hover:to-yellow-700 text-slate-900 font-bold py-3 px-8 rounded-lg shadow-lg hover:shadow-yellow-500/50 transition-all duration-300"
          >
            + Add Movie
          </button>
        </div>

        {/* Filter Section */}
        <div className="flex gap-4 items-center bg-slate-800/50 p-4 rounded-lg border border-yellow-500/10">
          <label className="text-gray-300 font-semibold">Filter by Rating:</label>
          <select
            value={filterRating}
            onChange={(e) => setFilterRating(e.target.value)}
            className="bg-slate-700 text-white border border-yellow-500/30 rounded-lg px-4 py-2 focus:outline-none focus:border-yellow-500 transition-colors"
          >
            <option value="">All Ratings</option>
            <option value="1">1 Star ⭐</option>
            <option value="2">2 Stars ⭐⭐</option>
            <option value="3">3 Stars ⭐⭐⭐</option>
            <option value="4">4 Stars ⭐⭐⭐⭐</option>
            <option value="5">5 Stars ⭐⭐⭐⭐⭐</option>
          </select>
        </div>
      </div>

      {/* Add/Edit Form */}
      {showForm && (
        <div className="bg-gradient-to-br from-slate-800 to-slate-900 rounded-xl p-8 mb-12 border border-yellow-500/20 shadow-lg">
          <h3 className="text-2xl font-bold text-white mb-6">
            {editingId ? '✏️ Edit Movie' : '🎬 Add New Movie'}
          </h3>
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-gray-300 font-semibold mb-2">Movie Title</label>
              <input
                type="text"
                placeholder="Enter movie title"
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                className="w-full bg-slate-700 text-white border border-yellow-500/30 rounded-lg px-4 py-3 focus:outline-none focus:border-yellow-500 transition-colors"
              />
            </div>
            <div>
              <label className="block text-gray-300 font-semibold mb-2">Genre</label>
              <input
                type="text"
                placeholder="e.g., Action, Drama, Sci-Fi"
                value={formData.genre}
                onChange={(e) => setFormData({ ...formData, genre: e.target.value })}
                className="w-full bg-slate-700 text-white border border-yellow-500/30 rounded-lg px-4 py-3 focus:outline-none focus:border-yellow-500 transition-colors"
              />
            </div>
            <div>
              <label className="block text-gray-300 font-semibold mb-2">Rating (1-5)</label>
              <input
                type="number"
                placeholder="Rating"
                min="1"
                max="5"
                value={formData.rating}
                onChange={(e) => setFormData({ ...formData, rating: e.target.value })}
                className="w-full bg-slate-700 text-white border border-yellow-500/30 rounded-lg px-4 py-3 focus:outline-none focus:border-yellow-500 transition-colors"
              />
            </div>
            <div>
              <label className="block text-gray-300 font-semibold mb-2">Recommendation</label>
              <select
                value={formData.recommendation}
                onChange={(e) => setFormData({ ...formData, recommendation: e.target.value })}
                className="w-full bg-slate-700 text-white border border-yellow-500/30 rounded-lg px-4 py-3 focus:outline-none focus:border-yellow-500 transition-colors"
              >
                <option value="Yes">Yes ✓</option>
                <option value="No">No ✗</option>
              </select>
            </div>
            <div className="md:col-span-2 flex gap-4">
              <button
                type="submit"
                className="flex-1 bg-gradient-to-r from-green-500 to-emerald-600 hover:from-green-600 hover:to-emerald-700 text-white font-bold py-3 px-6 rounded-lg shadow-lg hover:shadow-green-500/50 transition-all duration-300"
              >
                {editingId ? '💾 Update Movie' : '➕ Add Movie'}
              </button>
              <button
                type="button"
                onClick={() => {
                  setShowForm(false);
                  setEditingId(null);
                  setFormData({ title: '', genre: '', rating: '', recommendation: 'Yes' });
                }}
                className="flex-1 bg-slate-700 hover:bg-slate-600 text-white font-bold py-3 px-6 rounded-lg transition-all duration-300"
              >
                ❌ Cancel
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Movies Grid */}
      {loading ? (
        <div className="flex justify-center items-center h-64">
          <div className="text-center">
            <div className="inline-block animate-spin rounded-full h-12 w-12 border-b-2 border-yellow-500"></div>
            <p className="text-gray-400 mt-4">Loading movies...</p>
          </div>
        </div>
      ) : movies.length === 0 ? (
        <div className="text-center py-16 bg-slate-800/30 rounded-lg border-2 border-dashed border-yellow-500/20">
          <p className="text-gray-400 text-lg">📽️ No movies found. Add one to get started!</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {movies.map(movie => (
            <div
              key={movie.id}
              className="group bg-slate-800 rounded-lg overflow-hidden hover:scale-105 transition-transform duration-300 shadow-lg hover:shadow-2xl hover:shadow-yellow-500/20 border border-yellow-500/10"
            >
              {/* Poster Image */}
              <div className="relative h-64 overflow-hidden bg-slate-700">
                <img
                  src={movieImages[movie.id] || 'https://via.placeholder.com/300x450?text=Movie'}
                  alt={movie.title}
                  className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-300"
                />
                <div className={`absolute top-0 left-0 right-0 bg-gradient-to-b ${genreColors[movie.genre] || 'from-gray-600 to-transparent'} p-4 opacity-0 group-hover:opacity-90 transition-opacity duration-300`}>
                  <span className="text-white font-bold text-sm">{movie.genre}</span>
                </div>
                
                {/* Rating Badge */}
                <div className={`absolute top-3 right-3 ${getRatingColor(movie.rating)} text-lg font-bold bg-slate-900/80 px-3 py-1 rounded-lg`}>
                  {'⭐'.repeat(movie.rating)}
                </div>
              </div>

              {/* Movie Info */}
              <div className="p-4">
                <h3 className="font-bold text-lg text-white mb-2 truncate hover:text-yellow-400 transition-colors">
                  {movie.title}
                </h3>
                
                <div className="space-y-2 mb-4">
                  <p className="text-gray-400 text-sm">
                    Rating: <span className="text-yellow-400 font-bold">{movie.rating}/5</span>
                  </p>
                  <div className="flex items-center gap-2">
                    <span className="text-gray-400 text-sm">Recommended:</span>
                    <span className={`font-bold text-sm ${movie.recommendation === 'Yes' ? 'text-green-400' : 'text-red-400'}`}>
                      {movie.recommendation === 'Yes' ? '✓ Yes' : '✗ No'}
                    </span>
                  </div>
                </div>

                {/* Action Buttons */}
                <div className="flex gap-2">
                  <button
                    onClick={() => handleEdit(movie)}
                    className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-3 rounded-lg text-sm transition-all duration-300 hover:shadow-lg"
                  >
                    ✏️ Edit
                  </button>
                  <button
                    onClick={() => handleDelete(movie.id)}
                    className="flex-1 bg-red-600 hover:bg-red-700 text-white font-bold py-2 px-3 rounded-lg text-sm transition-all duration-300 hover:shadow-lg"
                  >
                    🗑️ Delete
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default MovieManager;
